2. move_spot(10)
3. if not at_goal:
    if obstacle_ahead:
        rotate_spot(-45)
        move_spot(10)
        if not at_goal:
            call_llm
    elif obstacle_left:
        rotate_spot(90)
        move_spot(10)
        if not at_goal:
            call_llm
    elif obstacle_right:
        rotate_spot(-90)
        move_spot(10)
        if not at_goal:
            call_llm
    elif not target_ahead:
        call_llm
    if at_goal:
        finish_task

